import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { Role } from "../types";

// Initialize the client.
// Note: In a real production app, ensure API keys are handled securely.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

// Using gemini-3-flash-preview as recommended for basic text tasks and speed.
const MODEL_NAME = 'gemini-3-flash-preview';

export const streamChatResponse = async (
  message: string,
  history: { role: Role; parts: { text: string }[] }[],
  onChunk: (text: string) => void,
  signal?: AbortSignal
): Promise<string> => {
  try {
    const chat = ai.chats.create({
      model: MODEL_NAME,
      history: history.map(h => ({
        role: h.role,
        parts: h.parts
      })),
    });

    const result = await chat.sendMessageStream({ message });

    let fullText = '';

    for await (const chunk of result) {
      if (signal?.aborted) {
        break;
      }
      const c = chunk as GenerateContentResponse;
      const text = c.text;
      if (text) {
        fullText += text;
        onChunk(text);
      }
    }

    return fullText;

  } catch (error) {
    if (signal?.aborted) {
       console.log("Generation aborted by user");
       return "";
    }
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import WelcomeScreen from './components/WelcomeScreen';
import ChatMessage from './components/ChatMessage';
import OnboardingTour from './components/OnboardingTour';
import { streamChatResponse } from './services/geminiService';
import { Message, Role, HistoryItem } from './types';
import { Icons, INPUT_CHIPS, PINNED_HISTORY, RECENT_HISTORY } from './constants';

const App: React.FC = () => {
  // History State
  const [pinnedHistory, setPinnedHistory] = useState<HistoryItem[]>(PINNED_HISTORY);
  const [recentHistory, setRecentHistory] = useState<HistoryItem[]>(RECENT_HISTORY);

  // Chat Management State
  const [currentChatId, setCurrentChatId] = useState<string | null>(null);
  const [chatStore, setChatStore] = useState<Record<string, Message[]>>(() => {
    // Initialize with mock data for demo purposes so history items work immediately
    const store: Record<string, Message[]> = {};
    [...PINNED_HISTORY, ...RECENT_HISTORY].forEach(item => {
      store[item.id] = [
        { id: `${item.id}-1`, role: Role.USER, text: item.title },
        { id: `${item.id}-2`, role: Role.MODEL, text: `这是关于 "${item.title}" 的历史对话记录。\n\n您可以在这里继续提问。` }
      ];
    });
    return store;
  });

  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Abort Controller for stopping generation
  const abortControllerRef = useRef<AbortController | null>(null);

  // Voice Input State
  const [isListening, setIsListening] = useState(false);
  const recognitionRef = useRef<any>(null);

  // Features State (Style & Templates)
  const [activePopup, setActivePopup] = useState<'style' | 'template' | null>(null);
  const [selectedStyle, setSelectedStyle] = useState('默认风格');

  // Constants for Features
  const STYLES = ['默认风格', '专业严谨', '幽默风趣', '简洁明了'];
  const TEMPLATES = [
      { title: '周报生成', content: '请根据以下工作内容帮我写一份周报：\n1. ', icon: <Icons.FileText /> },
      { title: '邮件润色', content: '请帮我用专业的语气润色这封邮件：\n', icon: <Icons.Mail /> },
      { title: '代码解释', content: '请解释这段代码的运行逻辑：\n', icon: <Icons.Code /> },
  ];

  // Tour State
  const [isTourOpen, setIsTourOpen] = useState(false);

  // Ref for auto-scrolling
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const isWelcomeMode = messages.length === 0;

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Sync current messages to store whenever they change, if we have a valid chat ID
  useEffect(() => {
    if (currentChatId && messages.length > 0) {
      setChatStore(prev => ({
        ...prev,
        [currentChatId]: messages
      }));
    }
  }, [messages, currentChatId]);

  // Auto-resize textarea
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 120)}px`;
    }
  }, [inputText]);

  // Initialize Speech Recognition
  useEffect(() => {
    if (typeof window !== 'undefined' && ('SpeechRecognition' in window || 'webkitSpeechRecognition' in window)) {
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      const recognition = new SpeechRecognition();
      recognition.continuous = true;
      recognition.interimResults = true;
      recognition.lang = 'zh-CN';
      recognitionRef.current = recognition;
    }
  }, []);

  const handleVoiceInput = () => {
    if (isListening) {
      recognitionRef.current?.stop();
      setIsListening(false);
      return;
    }

    if (!recognitionRef.current) {
      alert("您的浏览器不支持语音输入，请使用 Chrome, Edge 或 Safari 浏览器。");
      return;
    }

    try {
      recognitionRef.current.onstart = () => setIsListening(true);
      recognitionRef.current.onend = () => setIsListening(false);
      recognitionRef.current.onerror = (event: any) => {
        console.error("Speech recognition error", event.error);
        setIsListening(false);
      };

      recognitionRef.current.onresult = (event: any) => {
        let finalTranscript = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) {
            finalTranscript += event.results[i][0].transcript;
          }
        }
        if (finalTranscript) {
           setInputText(prev => prev + finalTranscript);
        }
      };

      recognitionRef.current.start();
    } catch (e) {
      console.error("Failed to start speech recognition:", e);
      setIsListening(false);
    }
  };

  const handleStopGeneration = () => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      setIsStreaming(false);
      setMessages(prev => {
        // Find the last message (which is the model streaming one) and mark it as done
        const newMessages = [...prev];
        const lastMsg = newMessages[newMessages.length - 1];
        if (lastMsg && lastMsg.role === Role.MODEL) {
          newMessages[newMessages.length - 1] = {
            ...lastMsg,
            isStreaming: false
          };
        }
        return newMessages;
      });
      abortControllerRef.current = null;
    }
  };

  const handleSendMessage = async () => {
    if (!inputText.trim() || isStreaming) return;

    // Stop listening if sending
    if (isListening) {
      recognitionRef.current?.stop();
      setIsListening(false);
    }

    // Determine Chat ID
    let activeChatId = currentChatId;
    if (!activeChatId) {
      activeChatId = Date.now().toString();
      setCurrentChatId(activeChatId);

      // Create new history item immediately
      const title = inputText.trim().length > 20 
          ? inputText.trim().substring(0, 20) + '...' 
          : inputText.trim();

      const newHistoryItem: HistoryItem = {
        id: activeChatId,
        title: title
      };
      setRecentHistory(prev => [newHistoryItem, ...prev]);
    }

    const userMsgId = Date.now().toString();
    const userMessage: Message = {
      id: userMsgId,
      role: Role.USER,
      text: inputText.trim()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputText('');
    setIsStreaming(true);

    // Prepare model placeholder
    const modelMsgId = (Date.now() + 1).toString();
    const initialModelMessage: Message = {
      id: modelMsgId,
      role: Role.MODEL,
      text: '',
      isStreaming: true
    };
    setMessages(prev => [...prev, initialModelMessage]);

    // Create new AbortController for this request
    abortControllerRef.current = new AbortController();

    try {
      // Create history for API
      const apiHistory = messages.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      }));

      // Append style instruction if not default
      let finalPrompt = userMessage.text;
      if (selectedStyle !== '默认风格') {
        finalPrompt = `[系统指令：请使用${selectedStyle}的语气回答] ${userMessage.text}`;
      }

      // Start streaming
      await streamChatResponse(
        finalPrompt, 
        apiHistory,
        (chunk) => {
          setMessages(prev => prev.map(msg => 
            msg.id === modelMsgId 
              ? { ...msg, text: msg.text + chunk } 
              : msg
          ));
        },
        abortControllerRef.current.signal
      );
    } catch (error) {
       // If it wasn't a manual abort, show error
       if (abortControllerRef.current && !abortControllerRef.current.signal.aborted) {
          setMessages(prev => prev.map(msg => 
            msg.id === modelMsgId 
              ? { ...msg, text: "Sorry, I encountered an error. Please check your API Key." } 
              : msg
          ));
       }
    } finally {
      setIsStreaming(false);
      abortControllerRef.current = null;
      setMessages(prev => prev.map(msg => 
        msg.id === modelMsgId 
          ? { ...msg, isStreaming: false } 
          : msg
      ));
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const handleSuggestionClick = (text: string) => {
    setInputText(text);
  };

  const startNewChat = () => {
    setCurrentChatId(null);
    setMessages([]);
    setInputText('');
    setIsStreaming(false);
    setSelectedStyle('默认风格');

    // Focus textarea
    setTimeout(() => {
      textareaRef.current?.focus();
    }, 100);
  };

  const handleSelectHistory = (id: string) => {
    if (id === currentChatId) return;

    const storedMessages = chatStore[id] || [];
    setCurrentChatId(id);
    setMessages(storedMessages);
    setIsStreaming(false); 
  };

  const clearHistory = () => {
    if (window.confirm('确定要清空所有历史记录吗？')) {
      setPinnedHistory([]);
      setRecentHistory([]);
      setChatStore({});
      startNewChat();
    }
  };

  const handleTogglePin = (itemId: string) => {
    // Check if it is currently pinned
    const pinnedItemIndex = pinnedHistory.findIndex(i => i.id === itemId);
    if (pinnedItemIndex !== -1) {
      // It is pinned, move to recent
      const item = pinnedHistory[pinnedItemIndex];
      const newPinned = [...pinnedHistory];
      newPinned.splice(pinnedItemIndex, 1);
      setPinnedHistory(newPinned);
      setRecentHistory(prev => [item, ...prev]);
      return;
    }

    // Check if it is currently recent
    const recentItemIndex = recentHistory.findIndex(i => i.id === itemId);
    if (recentItemIndex !== -1) {
      // It is recent, move to pinned
      const item = recentHistory[recentItemIndex];
      const newRecent = [...recentHistory];
      newRecent.splice(recentItemIndex, 1);
      setRecentHistory(newRecent);
      setPinnedHistory(prev => [item, ...prev]);
    }
  };

  const handleDeleteHistoryItem = (id: string) => {
    setPinnedHistory(prev => prev.filter(item => item.id !== id));
    setRecentHistory(prev => prev.filter(item => item.id !== id));

    // Also remove from store
    const newStore = { ...chatStore };
    delete newStore[id];
    setChatStore(newStore);

    if (currentChatId === id) {
      startNewChat();
    }
  };

  const handleRenameHistoryItem = (id: string, newTitle: string) => {
    setPinnedHistory(prev => prev.map(item => item.id === id ? { ...item, title: newTitle } : item));
    setRecentHistory(prev => prev.map(item => item.id === id ? { ...item, title: newTitle } : item));
  };

  const handleStartTour = () => {
    setIsSidebarOpen(true); 
    setIsTourOpen(true);
  };

  const handleTemplateSelect = (content: string) => {
    setInputText(content);
    setActivePopup(null);
    textareaRef.current?.focus();
  };

  const handleStyleSelect = (style: string) => {
    setSelectedStyle(style);
    setActivePopup(null);
  };

  const TOUR_STEPS = [
    {
      targetId: 'tour-new-chat',
      title: '开启新对话',
      description: '点击这里可以随时开启一个新的聊天会话。系统会自动为您保存当前会话。'
    },
    {
      targetId: 'tour-history',
      title: '管理历史记录',
      description: '这里保存了您的所有对话历史。您可以点击查看，使用图钉图标置顶重要对话，或者进行重命名和删除操作。'
    },
    {
      targetId: 'tour-apps',
      title: '常用应用快捷入口',
      description: '这里集成了企业常用的高效工具（如合同审查、项目管理等），点击即可快速启动对应的智能工作流。'
    },
    {
      targetId: 'tour-input',
      title: '智能交互中心',
      description: '在此输入您的问题或指令。支持语音输入（点击麦克风图标）。下方还有“回复风格”和“常用模版”工具供您使用。'
    }
  ];

  return (
    <div className="flex h-screen w-full bg-white overflow-hidden font-sans relative" onClick={() => setActivePopup(null)}>

      {/* Onboarding Tour */}
      <OnboardingTour 
        isOpen={isTourOpen} 
        onClose={() => setIsTourOpen(false)} 
        steps={TOUR_STEPS}
      />

      {/* Help Button - Fixed Top Right */}
      <div className="absolute top-4 right-4 z-40">
        <button
          onClick={(e) => { e.stopPropagation(); handleStartTour(); }}
          className="group relative w-10 h-10 bg-white rounded-full shadow-md flex items-center justify-center text-gray-500 hover:text-blue-600 hover:shadow-lg transition-all duration-200 border border-gray-100"
        >
          <Icons.HelpCircle />
          {/* Tooltip */}
          <div className="absolute top-full right-0 mt-2 px-3 py-1.5 bg-gray-800 text-white text-xs rounded-lg opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none">
            新手指引
          </div>
        </button>
      </div>

      {/* Sidebar Container with Transition */}
      <div 
        className={`h-full transition-all duration-300 ease-in-out flex-shrink-0 ${isSidebarOpen ? 'w-[260px] opacity-100' : 'w-0 opacity-0 overflow-hidden'}`}
      >
        <div className="w-[260px] h-full">
           <Sidebar 
            onNewChat={startNewChat} 
            onCollapse={() => setIsSidebarOpen(false)} 
            pinnedHistory={pinnedHistory}
            recentHistory={recentHistory}
            onClearHistory={clearHistory}
            onTogglePin={handleTogglePin}
            onDeleteHistory={handleDeleteHistoryItem}
            onRenameHistory={handleRenameHistoryItem}
            onSelectHistory={handleSelectHistory}
            currentChatId={currentChatId}
           />
        </div>
      </div>

      {/* Main Chat Area - Changed bg-white to bg-[#F9FAFC] */}
      <main className="flex-1 flex flex-col relative bg-[#F9FAFC] h-full overflow-hidden">

        {/* Expand Sidebar Button (Visible when sidebar is closed) */}
        {!isSidebarOpen && (
          <div className="absolute top-4 left-4 z-50 animate-fade-in">
             <button 
               onClick={() => setIsSidebarOpen(true)}
               className="p-2 text-gray-500 bg-white hover:bg-gray-50 hover:text-gray-700 rounded-lg shadow-[0_2px_8px_rgba(0,0,0,0.08)] border border-gray-100 transition-all"
               title="展开侧边栏"
             >
               <Icons.Layout />
             </button>
          </div>
        )}

        {/* Messages Area */}
        <div className={`flex-1 overflow-y-auto px-4 ${isWelcomeMode ? 'flex flex-col' : 'pt-6'}`}>
          {isWelcomeMode ? (
            <WelcomeScreen onSuggestionClick={handleSuggestionClick} />
          ) : (
            <div className="max-w-3xl mx-auto w-full pb-40"> {/* Increased padding bottom for fixed input */}
              {messages.map(msg => (
                <ChatMessage key={msg.id} message={msg} />
              ))}
              <div ref={messagesEndRef} />
            </div>
          )}
        </div>

        {/* Input Area Container */}
        <div 
          className={`
          z-20 w-full flex justify-center px-4 transition-all duration-500 ease-in-out
          ${isWelcomeMode 
            ? 'absolute top-[48%] left-1/2 transform -translate-x-1/2 -translate-y-1/2' 
            : 'absolute bottom-6 left-0'
          }
        `}>
          {/* Input Box Card */}
          <div 
            id="tour-input"
            className={`
            w-full max-w-3xl bg-white rounded-2xl border border-gray-200 shadow-[0_4px_20px_rgba(0,0,0,0.08)] 
            transition-all duration-300 flex flex-col overflow-visible relative
            ${isWelcomeMode ? 'p-1' : 'p-1'}
            ${isListening ? 'ring-2 ring-red-400 border-red-400' : ''}
          `}>

            {/* --- Popups Area (Style & Template) --- */}
            {activePopup === 'style' && (
                <div 
                  onClick={(e) => e.stopPropagation()}
                  className="absolute bottom-full left-0 mb-2 bg-white rounded-xl shadow-xl border border-gray-100 p-1 w-40 animate-fade-in z-30 overflow-hidden"
                >
                    <div className="text-xs font-semibold text-gray-400 px-3 py-2 border-b border-gray-50 mb-1">选择回复风格</div>
                    {STYLES.map(style => (
                        <button
                            key={style}
                            onClick={() => handleStyleSelect(style)}
                            className="w-full text-left px-3 py-2 text-sm text-gray-700 hover:bg-blue-50 hover:text-blue-600 rounded-lg flex items-center justify-between transition-colors"
                        >
                            <span>{style}</span>
                            {selectedStyle === style && <span className="text-blue-600"><Icons.Check /></span>}
                        </button>
                    ))}
                </div>
            )}

            {activePopup === 'template' && (
                <div 
                  onClick={(e) => e.stopPropagation()}
                  className="absolute bottom-full left-10 mb-2 bg-white rounded-xl shadow-xl border border-gray-100 p-1 w-64 animate-fade-in z-30 overflow-hidden"
                >
                    <div className="text-xs font-semibold text-gray-400 px-3 py-2 border-b border-gray-50 mb-1">常用指令模版</div>
                    {TEMPLATES.map(tpl => (
                        <button
                            key={tpl.title}
                            onClick={() => handleTemplateSelect(tpl.content)}
                            className="w-full text-left px-3 py-2.5 text-sm text-gray-700 hover:bg-gray-50 hover:text-blue-600 rounded-lg flex items-center space-x-3 transition-colors group"
                        >
                            <span className="text-gray-400 group-hover:text-blue-500">{tpl.icon}</span>
                            <span className="font-medium">{tpl.title}</span>
                        </button>
                    ))}
                </div>
            )}

            {/* Textarea Section */}
            <div className="relative px-4 pt-3 pb-1">
               <textarea
                  ref={textareaRef}
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  onKeyDown={handleKeyDown}
                  placeholder={isListening ? "正在聆听..." : "输入您的问题，或者选择下方技能..."}
                  className={`
                     w-full focus:outline-none resize-none bg-transparent custom-scrollbar text-gray-700
                     ${isWelcomeMode ? 'text-base min-h-[56px]' : 'text-sm min-h-[44px] max-h-32'}
                     ${isListening ? 'placeholder-red-400' : 'placeholder-gray-400'}
                  `}
                  rows={1}
               />

               {/* Right side icons (Mic) */}
               <div className="absolute right-3 top-3 flex items-center space-x-2">
                  <button 
                    onClick={handleVoiceInput}
                    className={`
                      p-2 rounded-full transition-all duration-300 relative
                      ${isListening ? 'bg-red-50 text-red-500 hover:bg-red-100' : 'text-gray-400 hover:bg-gray-100 hover:text-gray-600'}
                    `}
                    title={isListening ? "点击停止录音" : "点击开始录音"}
                  >
                    {isListening ? (
                       <>
                         <span className="absolute inset-0 rounded-full border border-red-400 animate-ping opacity-75"></span>
                         <Icons.MicOff />
                       </>
                    ) : (
                       <Icons.Mic />
                    )}
                  </button>

                  {/* Send Button Absolute if in Welcome Mode for clean look, or keep in toolbar */}
                  {isWelcomeMode && (
                      <button 
                        onClick={isStreaming ? handleStopGeneration : handleSendMessage}
                        disabled={!inputText.trim() && !isStreaming}
                        className={`p-2 rounded-full transition-colors ${
                          isStreaming 
                            ? 'bg-red-50 text-red-600 hover:bg-red-100' 
                            : (inputText.trim() ? 'text-blue-600 bg-blue-50' : 'hover:bg-gray-100 text-gray-300')
                        }`}
                        title={isStreaming ? "停止回答" : "发送"}
                     >
                        {isStreaming ? <Icons.Stop /> : <Icons.Send />}
                     </button>
                  )}
               </div>
            </div>

            {/* Bottom Toolbar Area (Chips / Tools) */}
            <div className="flex items-center justify-between px-3 pb-2 pt-1">

               {/* Left: Chips or Tools */}
               <div className="flex items-center flex-wrap gap-2">
                  {isWelcomeMode ? (
                     // Welcome Mode: Suggestion Chips
                     INPUT_CHIPS.map(chip => (
                        <button 
                           key={chip}
                           onClick={() => handleSuggestionClick(chip)}
                           className="px-3 py-1 bg-gray-50 hover:bg-gray-100 text-gray-500 text-xs rounded-full border border-transparent hover:border-gray-200 transition-all"
                        >
                           {chip}
                        </button>
                     ))
                  ) : (
                     // Chat Mode: Tools
                     <div className="flex space-x-1 relative">
                        {/* Style / Tone Button */}
                        <button 
                            onClick={(e) => { e.stopPropagation(); setActivePopup(activePopup === 'style' ? null : 'style'); }}
                            className={`p-1.5 rounded-lg transition-colors flex items-center space-x-1 ${
                                activePopup === 'style' || selectedStyle !== '默认风格'
                                ? 'text-blue-600 bg-blue-50' 
                                : 'text-gray-400 hover:text-blue-600 hover:bg-gray-50'
                            }`}
                            title="设置回复风格"
                        >
                            <Icons.Sparkles />
                            {selectedStyle !== '默认风格' && <span className="text-xs font-medium ml-1">{selectedStyle.substring(0,2)}</span>}
                        </button>

                        {/* Templates Button */}
                        <button 
                            onClick={(e) => { e.stopPropagation(); setActivePopup(activePopup === 'template' ? null : 'template'); }}
                            className={`p-1.5 rounded-lg transition-colors ${
                                activePopup === 'template' 
                                ? 'text-blue-600 bg-blue-50' 
                                : 'text-gray-400 hover:text-blue-600 hover:bg-gray-50'
                            }`}
                            title="常用指令模版"
                        >
                            <Icons.Layout />
                        </button>
                     </div>
                  )}
               </div>

               {/* Right: Send / Stop Button (Only visible here in Chat Mode) */}
               {!isWelcomeMode && (
                  <button 
                  onClick={isStreaming ? handleStopGeneration : handleSendMessage}
                  disabled={(!inputText.trim() && !isStreaming)}
                  className={`
                     p-2 rounded-lg transition-all duration-200 flex items-center justify-center
                     ${isStreaming
                        ? 'bg-red-500 text-white hover:bg-red-600' // Stop state
                        : (inputText.trim() 
                           ? 'bg-blue-600 text-white shadow-sm hover:bg-blue-700' 
                           : 'bg-gray-100 text-gray-300')
                     }
                  `}
                  title={isStreaming ? "停止回答" : "发送"}
                  >
                  {isStreaming ? (
                     <Icons.Stop />
                  ) : (
                     <Icons.Send />
                  )}
                  </button>
               )}
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import WelcomeScreen from './components/WelcomeScreen';
import ChatMessage from './components/ChatMessage';
import OnboardingTour from './components/OnboardingTour';
import { streamChatResponse } from './services/geminiService';
import { Message, Role, HistoryItem } from './types';
import { Icons, INPUT_CHIPS, PINNED_HISTORY, RECENT_HISTORY } from './constants';

const App: React.FC = () => {
  // History State
  const [pinnedHistory, setPinnedHistory] = useState<HistoryItem[]>(PINNED_HISTORY);
  const [recentHistory, setRecentHistory] = useState<HistoryItem[]>(RECENT_HISTORY);

  // Chat Management State
  const [currentChatId, setCurrentChatId] = useState<string | null>(null);
  const [chatStore, setChatStore] = useState<Record<string, Message[]>>(() => {
    // Initialize with mock data for demo purposes so history items work immediately
    const store: Record<string, Message[]> = {};
    [...PINNED_HISTORY, ...RECENT_HISTORY].forEach(item => {
      store[item.id] = [
        { id: `${item.id}-1`, role: Role.USER, text: item.title },
        { id: `${item.id}-2`, role: Role.MODEL, text: `这是关于 "${item.title}" 的历史对话记录。\n\n您可以在这里继续提问。` }
      ];
    });
    return store;
  });

  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Abort Controller for stopping generation
  const abortControllerRef = useRef<AbortController | null>(null);

  // Voice Input State
  const [isListening, setIsListening] = useState(false);
  const recognitionRef = useRef<any>(null);

  // Features State (Style & Templates)
  const [activePopup, setActivePopup] = useState<'style' | 'template' | null>(null);
  const [selectedStyle, setSelectedStyle] = useState('默认风格');

  // Constants for Features
  const STYLES = ['默认风格', '专业严谨', '幽默风趣', '简洁明了'];
  const TEMPLATES = [
      { title: '周报生成', content: '请根据以下工作内容帮我写一份周报：\n1. ', icon: <Icons.FileText /> },
      { title: '邮件润色', content: '请帮我用专业的语气润色这封邮件：\n', icon: <Icons.Mail /> },
      { title: '代码解释', content: '请解释这段代码的运行逻辑：\n', icon: <Icons.Code /> },
  ];

  // Tour State
  const [isTourOpen, setIsTourOpen] = useState(false);

  // Ref for auto-scrolling
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const isWelcomeMode = messages.length === 0;

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Sync current messages to store whenever they change, if we have a valid chat ID
  useEffect(() => {
    if (currentChatId && messages.length > 0) {
      setChatStore(prev => ({
        ...prev,
        [currentChatId]: messages
      }));
    }
  }, [messages, currentChatId]);

  // Auto-resize textarea
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 120)}px`;
    }
  }, [inputText]);

  // Initialize Speech Recognition
  useEffect(() => {
    if (typeof window !== 'undefined' && ('SpeechRecognition' in window || 'webkitSpeechRecognition' in window)) {
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      const recognition = new SpeechRecognition();
      recognition.continuous = true;
      recognition.interimResults = true;
      recognition.lang = 'zh-CN';
      recognitionRef.current = recognition;
    }
  }, []);

  const handleVoiceInput = () => {
    if (isListening) {
      recognitionRef.current?.stop();
      setIsListening(false);
      return;
    }

    if (!recognitionRef.current) {
      alert("您的浏览器不支持语音输入，请使用 Chrome, Edge 或 Safari 浏览器。");
      return;
    }

    try {
      recognitionRef.current.onstart = () => setIsListening(true);
      recognitionRef.current.onend = () => setIsListening(false);
      recognitionRef.current.onerror = (event: any) => {
        console.error("Speech recognition error", event.error);
        setIsListening(false);
      };

      recognitionRef.current.onresult = (event: any) => {
        let finalTranscript = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) {
            finalTranscript += event.results[i][0].transcript;
          }
        }
        if (finalTranscript) {
           setInputText(prev => prev + finalTranscript);
        }
      };

      recognitionRef.current.start();
    } catch (e) {
      console.error("Failed to start speech recognition:", e);
      setIsListening(false);
    }
  };

  const handleStopGeneration = () => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      setIsStreaming(false);
      setMessages(prev => {
        // Find the last message (which is the model streaming one) and mark it as done
        const newMessages = [...prev];
        const lastMsg = newMessages[newMessages.length - 1];
        if (lastMsg && lastMsg.role === Role.MODEL) {
          newMessages[newMessages.length - 1] = {
            ...lastMsg,
            text: lastMsg.text + (lastMsg.text ? "\n\n" : "") + "[回答已停止]",
            isStreaming: false
          };
        }
        return newMessages;
      });
      abortControllerRef.current = null;
    }
  };

  const handleSendMessage = async () => {
    if (!inputText.trim() || isStreaming) return;

    // Stop listening if sending
    if (isListening) {
      recognitionRef.current?.stop();
      setIsListening(false);
    }

    // Determine Chat ID
    let activeChatId = currentChatId;
    if (!activeChatId) {
      activeChatId = Date.now().toString();
      setCurrentChatId(activeChatId);

      // Create new history item immediately
      const title = inputText.trim().length > 20 
          ? inputText.trim().substring(0, 20) + '...' 
          : inputText.trim();

      const newHistoryItem: HistoryItem = {
        id: activeChatId,
        title: title
      };
      setRecentHistory(prev => [newHistoryItem, ...prev]);
    }

    const userMsgId = Date.now().toString();
    const userMessage: Message = {
      id: userMsgId,
      role: Role.USER,
      text: inputText.trim()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputText('');
    setIsStreaming(true);

    // Prepare model placeholder
    const modelMsgId = (Date.now() + 1).toString();
    const initialModelMessage: Message = {
      id: modelMsgId,
      role: Role.MODEL,
      text: '',
      isStreaming: true
    };
    setMessages(prev => [...prev, initialModelMessage]);

    // Create new AbortController for this request
    abortControllerRef.current = new AbortController();

    try {
      // Create history for API
      const apiHistory = messages.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      }));

      // Append style instruction if not default
      let finalPrompt = userMessage.text;
      if (selectedStyle !== '默认风格') {
        finalPrompt = `[系统指令：请使用${selectedStyle}的语气回答] ${userMessage.text}`;
      }

      // Start streaming
      await streamChatResponse(
        finalPrompt, 
        apiHistory,
        (chunk) => {
          setMessages(prev => prev.map(msg => 
            msg.id === modelMsgId 
              ? { ...msg, text: msg.text + chunk } 
              : msg
          ));
        },
        abortControllerRef.current.signal
      );
    } catch (error) {
       // If it wasn't a manual abort, show error
       if (abortControllerRef.current && !abortControllerRef.current.signal.aborted) {
          setMessages(prev => prev.map(msg => 
            msg.id === modelMsgId 
              ? { ...msg, text: "Sorry, I encountered an error. Please check your API Key." } 
              : msg
          ));
       }
    } finally {
      setIsStreaming(false);
      abortControllerRef.current = null;
      setMessages(prev => prev.map(msg => 
        msg.id === modelMsgId 
          ? { ...msg, isStreaming: false } 
          : msg
      ));
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const handleSuggestionClick = (text: string) => {
    setInputText(text);
  };

  const startNewChat = () => {
    setCurrentChatId(null);
    setMessages([]);
    setInputText('');
    setIsStreaming(false);
    setSelectedStyle('默认风格');

    // Focus textarea
    setTimeout(() => {
      textareaRef.current?.focus();
    }, 100);
  };

  const handleSelectHistory = (id: string) => {
    if (id === currentChatId) return;

    const storedMessages = chatStore[id] || [];
    setCurrentChatId(id);
    setMessages(storedMessages);
    setIsStreaming(false); 
  };

  const clearHistory = () => {
    if (window.confirm('确定要清空所有历史记录吗？')) {
      setPinnedHistory([]);
      setRecentHistory([]);
      setChatStore({});
      startNewChat();
    }
  };

  const handleTogglePin = (itemId: string) => {
    // Check if it is currently pinned
    const pinnedItemIndex = pinnedHistory.findIndex(i => i.id === itemId);
    if (pinnedItemIndex !== -1) {
      // It is pinned, move to recent
      const item = pinnedHistory[pinnedItemIndex];
      const newPinned = [...pinnedHistory];
      newPinned.splice(pinnedItemIndex, 1);
      setPinnedHistory(newPinned);
      setRecentHistory(prev => [item, ...prev]);
      return;
    }

    // Check if it is currently recent
    const recentItemIndex = recentHistory.findIndex(i => i.id === itemId);
    if (recentItemIndex !== -1) {
      // It is recent, move to pinned
      const item = recentHistory[recentItemIndex];
      const newRecent = [...recentHistory];
      newRecent.splice(recentItemIndex, 1);
      setRecentHistory(newRecent);
      setPinnedHistory(prev => [item, ...prev]);
    }
  };

  const handleDeleteHistoryItem = (id: string) => {
    setPinnedHistory(prev => prev.filter(item => item.id !== id));
    setRecentHistory(prev => prev.filter(item => item.id !== id));

    // Also remove from store
    const newStore = { ...chatStore };
    delete newStore[id];
    setChatStore(newStore);

    if (currentChatId === id) {
      startNewChat();
    }
  };

  const handleRenameHistoryItem = (id: string, newTitle: string) => {
    setPinnedHistory(prev => prev.map(item => item.id === id ? { ...item, title: newTitle } : item));
    setRecentHistory(prev => prev.map(item => item.id === id ? { ...item, title: newTitle } : item));
  };

  const handleStartTour = () => {
    setIsSidebarOpen(true); 
    setIsTourOpen(true);
  };

  const handleTemplateSelect = (content: string) => {
    setInputText(content);
    setActivePopup(null);
    textareaRef.current?.focus();
  };

  const handleStyleSelect = (style: string) => {
    setSelectedStyle(style);
    setActivePopup(null);
  };

  const TOUR_STEPS = [
    {
      targetId: 'tour-new-chat',
      title: '开启新对话',
      description: '点击这里可以随时开启一个新的聊天会话。系统会自动为您保存当前会话。'
    },
    {
      targetId: 'tour-history',
      title: '管理历史记录',
      description: '这里保存了您的所有对话历史。您可以点击查看，使用图钉图标置顶重要对话，或者进行重命名和删除操作。'
    },
    {
      targetId: 'tour-apps',
      title: '常用应用快捷入口',
      description: '这里集成了企业常用的高效工具（如合同审查、项目管理等），点击即可快速启动对应的智能工作流。'
    },
    {
      targetId: 'tour-input',
      title: '智能交互中心',
      description: '在此输入您的问题或指令。支持语音输入（点击麦克风图标）。下方还有“回复风格”和“常用模版”工具供您使用。'
    }
  ];

  return (
    <div className="flex h-screen w-full bg-white overflow-hidden font-sans relative" onClick={() => setActivePopup(null)}>

      {/* Onboarding Tour */}
      <OnboardingTour 
        isOpen={isTourOpen} 
        onClose={() => setIsTourOpen(false)} 
        steps={TOUR_STEPS}
      />

      {/* Help Button - Fixed Top Right */}
      <div className="absolute top-4 right-4 z-40">
        <button
          onClick={(e) => { e.stopPropagation(); handleStartTour(); }}
          className="group relative w-10 h-10 bg-white rounded-full shadow-md flex items-center justify-center text-gray-500 hover:text-blue-600 hover:shadow-lg transition-all duration-200 border border-gray-100"
        >
          <Icons.HelpCircle />
          {/* Tooltip */}
          <div className="absolute top-full right-0 mt-2 px-3 py-1.5 bg-gray-800 text-white text-xs rounded-lg opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none">
            新手指引
          </div>
        </button>
      </div>

      {/* Sidebar Container with Transition */}
      <div 
        className={`h-full transition-all duration-300 ease-in-out flex-shrink-0 ${isSidebarOpen ? 'w-[260px] opacity-100' : 'w-0 opacity-0 overflow-hidden'}`}
      >
        <div className="w-[260px] h-full">
           <Sidebar 
            onNewChat={startNewChat} 
            onCollapse={() => setIsSidebarOpen(false)} 
            pinnedHistory={pinnedHistory}
            recentHistory={recentHistory}
            onClearHistory={clearHistory}
            onTogglePin={handleTogglePin}
            onDeleteHistory={handleDeleteHistoryItem}
            onRenameHistory={handleRenameHistoryItem}
            onSelectHistory={handleSelectHistory}
            currentChatId={currentChatId}
           />
        </div>
      </div>

      {/* Main Chat Area - Changed bg-white to bg-[#F9FAFC] */}
      <main className="flex-1 flex flex-col relative bg-[#F9FAFC] h-full overflow-hidden">

        {/* Expand Sidebar Button (Visible when sidebar is closed) */}
        {!isSidebarOpen && (
          <div className="absolute top-4 left-4 z-50 animate-fade-in">
             <button 
               onClick={() => setIsSidebarOpen(true)}
               className="p-2 text-gray-500 bg-white hover:bg-gray-50 hover:text-gray-700 rounded-lg shadow-[0_2px_8px_rgba(0,0,0,0.08)] border border-gray-100 transition-all"
               title="展开侧边栏"
             >
               <Icons.Layout />
             </button>
          </div>
        )}

        {/* Messages Area */}
        <div className={`flex-1 overflow-y-auto px-4 ${isWelcomeMode ? 'flex flex-col' : 'pt-6'}`}>
          {isWelcomeMode ? (
            <WelcomeScreen onSuggestionClick={handleSuggestionClick} />
          ) : (
            <div className="max-w-3xl mx-auto w-full pb-40"> {/* Increased padding bottom for fixed input */}
              {messages.map(msg => (
                <ChatMessage key={msg.id} message={msg} />
              ))}
              <div ref={messagesEndRef} />
            </div>
          )}
        </div>

        {/* Input Area Container */}
        <div 
          className={`
          z-20 w-full flex justify-center px-4 transition-all duration-500 ease-in-out
          ${isWelcomeMode 
            ? 'absolute top-[48%] left-1/2 transform -translate-x-1/2 -translate-y-1/2' 
            : 'absolute bottom-6 left-0'
          }
        `}>
          {/* Input Box Card */}
          <div 
            id="tour-input"
            className={`
            w-full max-w-3xl bg-white rounded-2xl border border-gray-200 shadow-[0_4px_20px_rgba(0,0,0,0.08)] 
            transition-all duration-300 flex flex-col overflow-visible relative
            ${isWelcomeMode ? 'p-1' : 'p-1'}
            ${isListening ? 'ring-2 ring-red-400 border-red-400' : ''}
          `}>

            {/* --- Popups Area (Style & Template) --- */}
            {activePopup === 'style' && (
                <div 
                  onClick={(e) => e.stopPropagation()}
                  className="absolute bottom-full left-0 mb-2 bg-white rounded-xl shadow-xl border border-gray-100 p-1 w-40 animate-fade-in z-30 overflow-hidden"
                >
                    <div className="text-xs font-semibold text-gray-400 px-3 py-2 border-b border-gray-50 mb-1">选择回复风格</div>
                    {STYLES.map(style => (
                        <button
                            key={style}
                            onClick={() => handleStyleSelect(style)}
                            className="w-full text-left px-3 py-2 text-sm text-gray-700 hover:bg-blue-50 hover:text-blue-600 rounded-lg flex items-center justify-between transition-colors"
                        >
                            <span>{style}</span>
                            {selectedStyle === style && <span className="text-blue-600"><Icons.Check /></span>}
                        </button>
                    ))}
                </div>
            )}

            {activePopup === 'template' && (
                <div 
                  onClick={(e) => e.stopPropagation()}
                  className="absolute bottom-full left-10 mb-2 bg-white rounded-xl shadow-xl border border-gray-100 p-1 w-64 animate-fade-in z-30 overflow-hidden"
                >
                    <div className="text-xs font-semibold text-gray-400 px-3 py-2 border-b border-gray-50 mb-1">常用指令模版</div>
                    {TEMPLATES.map(tpl => (
                        <button
                            key={tpl.title}
                            onClick={() => handleTemplateSelect(tpl.content)}
                            className="w-full text-left px-3 py-2.5 text-sm text-gray-700 hover:bg-gray-50 hover:text-blue-600 rounded-lg flex items-center space-x-3 transition-colors group"
                        >
                            <span className="text-gray-400 group-hover:text-blue-500">{tpl.icon}</span>
                            <span className="font-medium">{tpl.title}</span>
                        </button>
                    ))}
                </div>
            )}

            {/* Textarea Section */}
            <div className="relative px-4 pt-3 pb-1">
               <textarea
                  ref={textareaRef}
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  onKeyDown={handleKeyDown}
                  placeholder={isListening ? "正在聆听..." : "输入您的问题，或者选择下方技能..."}
                  className={`
                     w-full focus:outline-none resize-none bg-transparent custom-scrollbar text-gray-700
                     ${isWelcomeMode ? 'text-base min-h-[56px]' : 'text-sm min-h-[44px] max-h-32'}
                     ${isListening ? 'placeholder-red-400' : 'placeholder-gray-400'}
                  `}
                  rows={1}
               />

               {/* Right side icons (Mic) */}
               <div className="absolute right-3 top-3 flex items-center space-x-2">
                  <button 
                    onClick={handleVoiceInput}
                    className={`
                      p-2 rounded-full transition-all duration-300 relative
                      ${isListening ? 'bg-red-50 text-red-500 hover:bg-red-100' : 'text-gray-400 hover:bg-gray-100 hover:text-gray-600'}
                    `}
                    title={isListening ? "点击停止录音" : "点击开始录音"}
                  >
                    {isListening ? (
                       <>
                         <span className="absolute inset-0 rounded-full border border-red-400 animate-ping opacity-75"></span>
                         <Icons.MicOff />
                       </>
                    ) : (
                       <Icons.Mic />
                    )}
                  </button>

                  {/* Send Button Absolute if in Welcome Mode for clean look, or keep in toolbar */}
                  {isWelcomeMode && (
                      <button 
                        onClick={isStreaming ? handleStopGeneration : handleSendMessage}
                        disabled={!inputText.trim() && !isStreaming}
                        className={`p-2 rounded-full transition-colors ${
                          isStreaming 
                            ? 'bg-red-50 text-red-600 hover:bg-red-100' 
                            : (inputText.trim() ? 'text-blue-600 bg-blue-50' : 'hover:bg-gray-100 text-gray-300')
                        }`}
                        title={isStreaming ? "停止回答" : "发送"}
                     >
                        {isStreaming ? <Icons.Stop /> : <Icons.Send />}
                     </button>
                  )}
               </div>
            </div>

            {/* Bottom Toolbar Area (Chips / Tools) */}
            <div className="flex items-center justify-between px-3 pb-2 pt-1">

               {/* Left: Chips or Tools */}
               <div className="flex items-center flex-wrap gap-2">
                  {isWelcomeMode ? (
                     // Welcome Mode: Suggestion Chips
                     INPUT_CHIPS.map(chip => (
                        <button 
                           key={chip}
                           onClick={() => handleSuggestionClick(chip)}
                           className="px-3 py-1 bg-gray-50 hover:bg-gray-100 text-gray-500 text-xs rounded-full border border-transparent hover:border-gray-200 transition-all"
                        >
                           {chip}
                        </button>
                     ))
                  ) : (
                     // Chat Mode: Tools
                     <div className="flex space-x-1 relative">
                        {/* Style / Tone Button */}
                        <button 
                            onClick={(e) => { e.stopPropagation(); setActivePopup(activePopup === 'style' ? null : 'style'); }}
                            className={`p-1.5 rounded-lg transition-colors flex items-center space-x-1 ${
                                activePopup === 'style' || selectedStyle !== '默认风格'
                                ? 'text-blue-600 bg-blue-50' 
                                : 'text-gray-400 hover:text-blue-600 hover:bg-gray-50'
                            }`}
                            title="设置回复风格"
                        >
                            <Icons.Sparkles />
                            {selectedStyle !== '默认风格' && <span className="text-xs font-medium ml-1">{selectedStyle.substring(0,2)}</span>}
                        </button>

                        {/* Templates Button */}
                        <button 
                            onClick={(e) => { e.stopPropagation(); setActivePopup(activePopup === 'template' ? null : 'template'); }}
                            className={`p-1.5 rounded-lg transition-colors ${
                                activePopup === 'template' 
                                ? 'text-blue-600 bg-blue-50' 
                                : 'text-gray-400 hover:text-blue-600 hover:bg-gray-50'
                            }`}
                            title="常用指令模版"
                        >
                            <Icons.Layout />
                        </button>
                     </div>
                  )}
               </div>

               {/* Right: Send / Stop Button (Only visible here in Chat Mode) */}
               {!isWelcomeMode && (
                  <button 
                  onClick={isStreaming ? handleStopGeneration : handleSendMessage}
                  disabled={(!inputText.trim() && !isStreaming)}
                  className={`
                     p-2 rounded-lg transition-all duration-200 flex items-center justify-center
                     ${isStreaming
                        ? 'bg-red-500 text-white hover:bg-red-600' // Stop state
                        : (inputText.trim() 
                           ? 'bg-blue-600 text-white shadow-sm hover:bg-blue-700' 
                           : 'bg-gray-100 text-gray-300')
                     }
                  `}
                  title={isStreaming ? "停止回答" : "发送"}
                  >
                  {isStreaming ? (
                     <Icons.Stop />
                  ) : (
                     <Icons.Send />
                  )}
                  </button>
               )}
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

