import React, { useState } from 'react';
import { Message, Role } from '../types';
import { Icons } from '../constants';

interface ChatMessageProps {
  message: Message;
  onRegenerate?: (id: string) => void;
}

const ChatMessage: React.FC<ChatMessageProps> = ({ message, onRegenerate }) => {
  const isUser = message.role === Role.USER;
  const showThinking = !isUser && message.isStreaming;

  const [isCopied, setIsCopied] = useState(false);
  const [feedback, setFeedback] = useState<'up' | 'down' | null>(null);

  const handleCopy = () => {
    navigator.clipboard.writeText(message.text).then(() => {
      setIsCopied(true);
      setTimeout(() => setIsCopied(false), 2000);
    });
  };

  const handleFeedback = (type: 'up' | 'down') => {
    setFeedback(prev => prev === type ? null : type);
  };

  return (
    <div className={`flex w-full mb-6 ${isUser ? 'justify-end' : 'justify-start'}`}>
      <div className={`flex max-w-[80%] ${isUser ? 'flex-row-reverse' : 'flex-row items-start'}`}>
        {/* Avatar */}
        <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 mt-1 ${isUser ? 'ml-3 bg-blue-600 text-white' : 'mr-3 bg-white border border-gray-200'}`}>
          {isUser ? <Icons.User /> : 
             <div className="w-5 h-5 flex items-center justify-center">
                 <Icons.YanfuLogo />
             </div>
          }
        </div>

        {/* Content Column */}
        <div className={`flex flex-col ${isUser ? 'items-end' : 'items-start'} min-w-0`}>

          {/* Thinking Indicator */}
          {showThinking && (
            <div className="flex items-center space-x-2 mb-2 px-1 animate-pulse">
               <div className="text-blue-500">
                  <Icons.Sparkles />
               </div>
               <span className="text-xs font-medium text-blue-500">思考中...</span>
            </div>
          )}

          {/* Message Bubble */}
          <div className={`p-4 rounded-2xl text-sm leading-relaxed shadow-sm whitespace-pre-wrap break-words ${
            isUser 
              ? 'bg-blue-600 text-white rounded-tr-none' 
              : 'bg-white border border-gray-100 text-gray-800 rounded-tl-none'
          }`}>
            {message.text}
            {message.isStreaming && (
              <span className="inline-block w-1.5 h-4 ml-1 bg-blue-400 animate-pulse align-middle"></span>
            )}
            {/* Ensure bubble has height even if empty */}
            {!message.text && message.isStreaming && <span className="opacity-0">...</span>}
          </div>

          {/* Action Bar (Only for Model, Not Streaming) */}
          {!isUser && !message.isStreaming && (
             <div className="flex items-center space-x-1 mt-1.5 ml-1 select-none animate-fade-in">

                {/* Copy Button */}
                <button 
                  onClick={handleCopy}
                  className="p-1.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-lg transition-colors flex items-center gap-1 group"
                  title="复制内容"
                >
                  {isCopied ? <span className="text-green-500"><Icons.Check /></span> : <Icons.Copy />}
                  {isCopied && <span className="text-xs text-green-500 font-medium">已复制</span>}
                </button>

                {/* Regenerate Button */}
                {onRegenerate && (
                  <button 
                    onClick={() => onRegenerate(message.id)}
                    className="p-1.5 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors group"
                    title="重新回答"
                  >
                    <Icons.Refresh />
                  </button>
                )}

                <div className="w-[1px] h-3 bg-gray-200 mx-1"></div>

                {/* Thumbs Up */}
                <button 
                  onClick={() => handleFeedback('up')}
                  className={`p-1.5 rounded-lg transition-colors ${
                     feedback === 'up' 
                     ? 'text-orange-500 bg-orange-50' 
                     : 'text-gray-400 hover:text-gray-600 hover:bg-gray-100'
                  }`}
                  title="赞同"
                >
                  <Icons.ThumbsUp />
                </button>

                {/* Thumbs Down */}
                <button 
                  onClick={() => handleFeedback('down')}
                  className={`p-1.5 rounded-lg transition-colors ${
                     feedback === 'down' 
                     ? 'text-gray-700 bg-gray-100' 
                     : 'text-gray-400 hover:text-gray-600 hover:bg-gray-100'
                  }`}
                  title="反对"
                >
                  <Icons.ThumbsDown />
                </button>
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ChatMessage;

