import React, { useState } from 'react';
import { COMMON_APPS, Icons } from '../constants';
import { HistoryItem } from '../types';

interface SidebarProps {
  onNewChat: () => void;
  onCollapse: () => void;
  onClearHistory: () => void;
  onSelectHistory: (id: string) => void;
  onTogglePin: (id: string) => void;
  onDeleteHistory: (id: string) => void;
  onRenameHistory: (id: string, newTitle: string) => void;
  pinnedHistory: HistoryItem[];
  recentHistory: HistoryItem[];
  currentChatId: string | null;
}

const Sidebar: React.FC<SidebarProps> = ({ 
  onNewChat, 
  onCollapse, 
  onClearHistory,
  onSelectHistory,
  onTogglePin,
  onDeleteHistory,
  onRenameHistory,
  pinnedHistory,
  recentHistory,
  currentChatId
}) => {
  const hasHistory = pinnedHistory.length > 0 || recentHistory.length > 0;

  // State for Rename
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');

  // State for Delete Confirmation Modal
  const [deleteTargetId, setDeleteTargetId] = useState<string | null>(null);

  // --- Rename Logic ---
  const startEditing = (e: React.MouseEvent, item: HistoryItem) => {
    e.stopPropagation();
    setEditingId(item.id);
    setEditTitle(item.title);
  };

  const cancelEditing = () => {
    setEditingId(null);
    setEditTitle('');
  };

  const saveEditing = () => {
    if (editingId && editTitle.trim()) {
      onRenameHistory(editingId, editTitle.trim());
    }
    cancelEditing();
  };

  // --- Delete Logic ---
  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setDeleteTargetId(id);
  };

  const confirmDelete = () => {
    if (deleteTargetId) {
      onDeleteHistory(deleteTargetId);
      setDeleteTargetId(null);
    }
  };

  const cancelDelete = () => {
    setDeleteTargetId(null);
  };

  // --- Event Handlers ---
  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      saveEditing();
    } else if (e.key === 'Escape') {
      cancelEditing();
    }
  };

  const renderHistoryItem = (item: HistoryItem, isPinned: boolean) => {
    const isEditing = editingId === item.id;
    const isActive = item.id === currentChatId;

    if (isEditing) {
      return (
        <div key={item.id} className="flex items-center px-3 py-2 bg-blue-50 rounded-lg mb-0.5 border border-blue-200">
           <div className="w-full flex items-center">
             <input
               autoFocus
               type="text"
               value={editTitle}
               onChange={(e) => setEditTitle(e.target.value)}
               onBlur={saveEditing}
               onKeyDown={handleKeyDown}
               className="w-full bg-transparent text-sm text-gray-800 focus:outline-none"
             />
           </div>
        </div>
      );
    }

    return (
      <div 
        key={item.id} 
        onClick={() => onSelectHistory(item.id)}
        className={`group flex items-center px-3 py-2 rounded-lg cursor-pointer transition-colors text-gray-600 mb-0.5 relative ${isActive ? 'bg-blue-50 text-blue-600' : 'hover:bg-gray-100'}`}
      >
        <span className={`mr-2.5 transform scale-90 ${isPinned ? 'text-blue-500' : (isActive ? 'text-blue-500' : 'text-gray-300 group-hover:text-gray-400')}`}>
          {isPinned ? <Icons.Pin /> : <Icons.Clock />}
        </span>
        <span className={`truncate flex-1 text-sm pr-14 ${isActive ? 'font-medium' : ''}`}>{item.title}</span>

        {/* Actions Container */}
        <div className={`absolute right-2 flex items-center transition-all rounded ${isActive ? 'bg-blue-50' : 'bg-gray-100 opacity-0 group-hover:opacity-100'}`}>
           {/* Edit Button */}
           <button
              onClick={(e) => startEditing(e, item)}
              className={`p-1 rounded transition-colors ${isActive ? 'text-blue-400 hover:text-blue-600 hover:bg-blue-100' : 'hover:bg-gray-200 text-gray-400 hover:text-blue-600'}`}
              title="重命名"
           >
              <Icons.Edit />
           </button>

           {/* Delete Button */}
           <button
              onClick={(e) => handleDeleteClick(e, item.id)}
              className={`p-1 rounded transition-colors ml-0.5 ${isActive ? 'text-blue-400 hover:text-red-500 hover:bg-blue-100' : 'hover:bg-gray-200 text-gray-400 hover:text-red-500'}`}
              title="删除"
           >
              <Icons.Trash />
           </button>

           {/* Toggle Pin Button */}
           <button
              onClick={(e) => { e.stopPropagation(); onTogglePin(item.id); }}
              className={`p-1 rounded transition-colors ml-0.5 ${isActive ? 'text-blue-400 hover:text-blue-600 hover:bg-blue-100' : 'hover:bg-gray-200 text-gray-400 hover:text-gray-600'}`}
              title={isPinned ? "取消置顶" : "置顶"}
           >
              {isPinned ? <Icons.PinOff /> : <Icons.Pin />}
           </button>
        </div>
      </div>
    );
  };

  return (
    <>
      <div className="w-[260px] h-full bg-white border-r border-gray-200 flex flex-col text-sm text-gray-700 flex-shrink-0 relative z-10 shadow-[2px_0_8px_rgba(0,0,0,0.04)]">
        {/* Header */}
        <div className="h-16 flex items-center justify-between px-4 border-b border-gray-50 flex-shrink-0">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 flex items-center justify-center">
              <div className="transform scale-110">
                  <Icons.YanfuLogo />
              </div>
            </div>
            <span className="font-bold text-gray-800 text-base tracking-tight">言复智能助手</span>
          </div>
          <button 
            onClick={onCollapse}
            className="text-gray-400 hover:text-gray-600 p-1.5 hover:bg-gray-100 rounded-md transition-colors"
            title="收起侧边栏"
          >
            <Icons.Layout />
          </button>
        </div>

        {/* New Chat Button */}
        <div className="p-4 pb-2 flex-shrink-0" id="tour-new-chat">
          <button 
            onClick={onNewChat}
            className="w-full bg-[#0f172a] hover:bg-[#1e293b] text-white rounded-lg py-2.5 px-4 flex items-center justify-center space-x-2 shadow-md hover:shadow-lg transition-all duration-200 group"
          >
            <Icons.Plus />
            <span className="font-medium">新建对话</span>
          </button>
        </div>

        {/* Main Split Content Area */}
        <div className="flex-1 flex flex-col min-h-0 overflow-hidden">

          {/* Top Section: History (50%) */}
          <div className="flex-1 overflow-y-auto px-2 custom-scrollbar min-h-0 border-b border-gray-100" id="tour-history">
            {hasHistory && (
              <div className="mt-2 mb-2">
                <div className="px-3 py-2 flex items-center text-xs text-gray-400 font-medium justify-between group">
                    <span>最近历史</span>
                    <button 
                      onClick={(e) => {
                        e.stopPropagation();
                        if (window.confirm('确定要清空所有历史记录吗？')) {
                          onClearHistory();
                        }
                      }}
                      className="cursor-pointer hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity p-1"
                      title="清空记录"
                    >
                      <Icons.Trash />
                    </button>
                </div>

                {/* Pinned Items */}
                {pinnedHistory.map(item => renderHistoryItem(item, true))}

                {/* Recent Items */}
                {recentHistory.map(item => renderHistoryItem(item, false))}
              </div>
            )}
          </div>

          {/* Bottom Section: Common Apps (50%) */}
          <div className="flex-1 overflow-y-auto min-h-0 custom-scrollbar bg-white" id="tour-apps">
            <div className="px-2 py-4">
              <div className="px-3 py-1 text-xs text-gray-400 font-medium mb-2">常用应用</div>
              {COMMON_APPS.map(app => (
                <div key={app.id} className="flex items-center px-3 py-2 hover:bg-gray-100 rounded-lg cursor-pointer transition-colors mb-1">
                  <div className={`w-6 h-6 rounded-md flex items-center justify-center text-sm mr-3 ${app.color}`}>
                    {app.icon}
                  </div>
                  <span className="truncate flex-1 text-gray-700 text-sm">{app.name}</span>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* User Footer - Fixed */}
        <div className="p-4 border-t border-gray-100 flex-shrink-0 bg-white">
          <div className="flex items-center space-x-3 cursor-pointer hover:bg-gray-50 p-2 rounded-xl transition-colors">
            <div className="w-8 h-8 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center text-xs font-bold border border-blue-200">
              U
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-sm font-medium text-gray-700 truncate">Admin User</p>
            </div>
            <div className="text-gray-400">
              <Icons.MoreHorizontal />
            </div>
          </div>
        </div>
      </div>

      {/* Delete Confirmation Modal */}
      {deleteTargetId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/20 backdrop-blur-[2px] animate-fade-in">
          <div className="bg-white rounded-2xl shadow-[0_10px_40px_rgba(0,0,0,0.1)] w-full max-w-[320px] overflow-hidden transform transition-all scale-100 ring-1 ring-gray-100">
            <div className="p-6 text-center">
              <div className="w-12 h-12 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-4 text-red-500">
                <Icons.Trash />
              </div>
              <h3 className="text-lg font-bold text-gray-900 mb-2">删除对话</h3>
              <p className="text-sm text-gray-500 leading-relaxed">
                确定要删除这条对话记录吗？<br/>此操作无法撤销。
              </p>
            </div>
            <div className="flex border-t border-gray-100 divide-x divide-gray-100">
              <button 
                onClick={cancelDelete}
                className="flex-1 py-3 text-sm font-medium text-gray-600 hover:bg-gray-50 transition-colors"
              >
                取消
              </button>
              <button 
                onClick={confirmDelete}
                className="flex-1 py-3 text-sm font-bold text-red-600 hover:bg-red-50 transition-colors"
              >
                删除
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default Sidebar;

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { Role } from "../types";

// Initialize the client.
// Note: In a real production app, ensure API keys are handled securely.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

// Using gemini-3-flash-preview as recommended for basic text tasks and speed.
const MODEL_NAME = 'gemini-3-flash-preview';

export const streamChatResponse = async (
  message: string,
  history: { role: Role; parts: { text: string }[] }[],
  onChunk: (text: string) => void,
  signal?: AbortSignal
): Promise<string> => {
  try {
    const chat = ai.chats.create({
      model: MODEL_NAME,
      history: history.map(h => ({
        role: h.role,
        parts: h.parts
      })),
    });

    const result = await chat.sendMessageStream({ message });

    let fullText = '';

    for await (const chunk of result) {
      if (signal?.aborted) {
        break;
      }
      const c = chunk as GenerateContentResponse;
      const text = c.text;
      if (text) {
        fullText += text;
        onChunk(text);
      }
    }

    return fullText;

  } catch (error: any) {
    if (signal?.aborted) {
       console.log("Generation aborted by user");
       return "";
    }

    // Handle Region/Permission Errors gracefully for demo/delivery
    // 403 PERMISSION_DENIED or specific message
    if (error.status === 403 || (error.message && error.message.includes('Region not supported'))) {
      console.warn("Gemini API Region blocked. Switching to mock response.");

      const mockResponse = "检测到当前网络环境无法直接访问 Gemini API (区域限制)。\n\n**这是一个模拟回复**，旨在展示界面交互效果。\n\n言复智能助手可以帮助您：\n1. 📈 **智能分析**：解读复杂的销售报表与市场趋势\n2. 📝 **内容创作**：生成周报、润色邮件或编写代码\n3. ⚡ **效率工具**：快速检索知识库与企业数据\n\n(请在支持的地区或配置代理后连接真实模型)";

      // Simulate streaming effect
      const chars = mockResponse.split('');
      let currentText = '';

      for (let i = 0; i < chars.length; i++) {
        if (signal?.aborted) break;
        await new Promise(resolve => setTimeout(resolve, 20)); // Typing speed
        currentText += chars[i];
        onChunk(chars[i]);
      }
      return mockResponse;
    }

    console.error("Gemini API Error:", error);
    throw error;
  }
};

