        key={item.id} 
        onClick={() => onSelectHistory(item.id)}
        className={`group flex items-center px-3 py-2.5 rounded-lg cursor-pointer transition-all text-gray-600 mb-0.5 relative ${isActive ? 'bg-blue-50 text-blue-700 font-medium' : 'hover:bg-gray-100'}`}
      >
        {/* Active Indicator Bar */}
        {isActive && <div className="absolute left-0 top-1/2 transform -translate-y-1/2 w-1 h-4 bg-blue-600 rounded-r-full"></div>}

        <span className={`mr-3 transform scale-90 ${isPinned ? 'text-blue-500' : (isActive ? 'text-blue-500' : 'text-gray-400 group-hover:text-gray-500')}`}>
          {isPinned ? <Icons.Pin /> : <Icons.Clock />}
        </span>
        <span className="truncate flex-1 text-sm pr-14">{item.title}</span>

        {/* Actions Container */}
        <div className={`absolute right-2 flex items-center transition-all rounded ${isActive ? 'bg-blue-50' : 'bg-gray-100 opacity-0 group-hover:opacity-100'}`}>
           {/* Edit Button */}
           <button
              onClick={(e) => startEditing(e, item)}
              className={`p-1 rounded transition-colors ${isActive ? 'text-blue-400 hover:text-blue-600 hover:bg-blue-100' : 'hover:bg-gray-200 text-gray-400 hover:text-blue-600'}`}
              title="重命名"
           >
              <Icons.Edit />
           </button>

           {/* Delete Button */}
           <button
              onClick={(e) => handleDeleteClick(e, item.id)}
              className={`p-1 rounded transition-colors ml-0.5 ${isActive ? 'text-blue-400 hover:text-red-500 hover:bg-blue-100' : 'hover:bg-gray-200 text-gray-400 hover:text-red-500'}`}
              title="删除"
           >
              <Icons.Trash />
           </button>

           {/* Toggle Pin Button */}
           <button
              onClick={(e) => { e.stopPropagation(); onTogglePin(item.id); }}
              className={`p-1 rounded transition-colors ml-0.5 ${isActive ? 'text-blue-400 hover:text-blue-600 hover:bg-blue-100' : 'hover:bg-gray-200 text-gray-400 hover:text-gray-600'}`}
              title={isPinned ? "取消置顶" : "置顶"}
           >
              {isPinned ? <Icons.PinOff /> : <Icons.Pin />}
           </button>
        </div>
      </div>
    );
  };

  return (
    <>
      <div className="w-[260px] h-full bg-white border-r border-gray-200 flex flex-col text-sm text-gray-700 flex-shrink-0 relative z-10 shadow-[4px_0_24px_rgba(0,0,0,0.02)]">
        {/* Header */}
        <div className="h-16 flex items-center justify-between px-5 border-b border-gray-50 flex-shrink-0">
          <div className="flex items-center space-x-2.5">
            <div className="w-8 h-8 flex items-center justify-center">
              <div className="transform scale-110">
                  <Icons.YanfuLogo />
              </div>
            </div>
            <span className="font-bold text-gray-800 text-base tracking-tight font-sans">言复智能</span>
          </div>
          <button 
            onClick={onCollapse}
            className="text-gray-400 hover:text-gray-600 p-1.5 hover:bg-gray-100 rounded-md transition-colors"
            title="收起侧边栏"
          >
            <Icons.Layout />
          </button>
        </div>

        {/* New Chat Button */}
        <div className="p-4 pb-2 flex-shrink-0" id="tour-new-chat">
          <button 
            onClick={onNewChat}
            className="w-full bg-gradient-to-r from-gray-800 to-gray-900 hover:from-black hover:to-gray-900 text-white rounded-xl py-3 px-4 flex items-center justify-center space-x-2 shadow-lg shadow-gray-200 hover:shadow-xl hover:shadow-gray-300 transition-all duration-300 group transform hover:-translate-y-0.5"
          >
            <Icons.Plus />
            <span className="font-semibold tracking-wide">新建对话</span>
          </button>
        </div>

        {/* Main Split Content Area */}
        <div className="flex-1 flex flex-col min-h-0 overflow-hidden">

          {/* Top Section: History (60%) */}
          <div className="flex-1 overflow-y-auto px-3 custom-scrollbar min-h-0" id="tour-history">
            {hasHistory && (
              <div className="mt-4 mb-2">
                <div className="px-3 py-2 flex items-center text-xs text-gray-400 font-semibold uppercase tracking-wider justify-between group">
                    <span>历史记录</span>
                    <button 
                      onClick={(e) => {
                        e.stopPropagation();
                        if (window.confirm('确定要清空所有历史记录吗？')) {
                          onClearHistory();
                        }
                      }}
                      className="cursor-pointer hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity p-1"
                      title="清空记录"
                    >
                      <Icons.Trash />
                    </button>
                </div>

                {/* Pinned Items */}
                {pinnedHistory.map(item => renderHistoryItem(item, true))}

                {/* Recent Items */}
                {recentHistory.map(item => renderHistoryItem(item, false))}
              </div>
            )}
          </div>

          {/* Bottom Section: Common Apps (Fixed height or smaller portion) */}
          <div className="flex-shrink-0 overflow-y-auto min-h-0 custom-scrollbar bg-gray-50/50 border-t border-gray-100 pb-2" id="tour-apps">
            <div className="px-3 py-4">
              <div className="px-3 py-1 text-xs text-gray-400 font-semibold uppercase tracking-wider mb-2">常用应用</div>
              {COMMON_APPS.map(app => (
                <div key={app.id} className="flex items-center px-3 py-2.5 hover:bg-white hover:shadow-sm rounded-xl cursor-pointer transition-all mb-1 group border border-transparent hover:border-gray-100">
                  <div className={`w-7 h-7 rounded-lg flex items-center justify-center text-sm mr-3 ${app.color} bg-opacity-15`}>
                    {app.icon}
                  </div>
                  <span className="truncate flex-1 text-gray-700 text-sm font-medium group-hover:text-gray-900">{app.name}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* Delete Confirmation Modal */}
      {deleteTargetId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-gray-900/20 backdrop-blur-sm animate-fade-in">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-[320px] overflow-hidden transform transition-all scale-100 ring-1 ring-black/5">
            <div className="p-6 text-center">
              <div className="w-12 h-12 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-4 text-red-500 ring-4 ring-red-50">
                <Icons.Trash />
              </div>
              <h3 className="text-lg font-bold text-gray-900 mb-2">删除对话</h3>
              <p className="text-sm text-gray-500 leading-relaxed">
                确定要删除这条对话记录吗？<br/>此操作无法撤销。
              </p>
            </div>
            <div className="flex border-t border-gray-100 divide-x divide-gray-100 bg-gray-50">
              <button 
                onClick={cancelDelete}
                className="flex-1 py-3 text-sm font-medium text-gray-600 hover:bg-white hover:text-gray-800 transition-colors"
              >
                取消
              </button>
              <button 
                onClick={confirmDelete}
                className="flex-1 py-3 text-sm font-bold text-red-600 hover:bg-red-50 transition-colors"
              >
                删除
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default Sidebar;
